-- Add a reusable 150-word China housing and daily-life deck with pre-generated audio.
insert into public.template_decks (slug, name, description, level)
values (
  'thue-nha-sinh-hoat-trung-quoc-150',
  'Thuê nhà và sinh hoạt tại Trung Quốc - 150 từ',
  '150 từ vựng tiếng Trung thực tế về tìm và thuê nhà, tiền nhà, điện nước, hợp đồng, sửa chữa, hàng xóm, giao hàng và chuyển nhà. Mỗi từ có pinyin, nghĩa tiếng Việt, câu ví dụ theo ngữ cảnh và hai audio tạo sẵn.',
  'Thuê nhà'
)
on conflict (slug) do update
set name = excluded.name, description = excluded.description, level = excluded.level;

with target_deck as (
  select id from public.template_decks where slug = 'thue-nha-sinh-hoat-trung-quoc-150'
)
insert into public.template_cards (
  template_deck_id, chinese, pinyin, meaning_vi, example_cn,
  example_pinyin, example_vi, word_audio_url, sentence_audio_url, position
)
select
  target_deck.id, card.chinese, card.pinyin, card.meaning_vi,
  card.example_cn, card.example_pinyin, card.example_vi,
  card.word_audio_url, card.sentence_audio_url, card.position
from target_deck
cross join (
  values
    ('房源', 'fángyuán', 'tin đăng nhà cho thuê, nguồn nhà đang cho thuê', '我们今天在网上找了几个不错的房源。', 'Wǒmen jīntiān zài wǎngshàng zhǎole jǐ gè bùcuò de fángyuán.', 'Hôm nay chúng tôi đã tìm được vài nguồn nhà tốt trên mạng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-29c56b31042cee809cd5c37e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-20edd6c09d48dc5ea0238eb4.mp3', 1),
    ('租房', 'zūfáng', 'thuê nhà', '他打算下个月开始租房，距离公司近一点。', 'Tā dǎsuàn xià gè yuè kāishǐ zūfáng, jùlí gōngsī jìn yīdiǎn.', 'Anh ấy dự định tháng sau bắt đầu thuê nhà, gần công ty một chút.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ad59363e4cf9ffdb9d9074e4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-fa78588b1ffe063df30d54da.mp3', 2),
    ('看房', 'kànfáng', 'xem nhà', '周末我们约了中介去看房。', 'Zhōumò wǒmen yuēle zhōngjiè qù kànfáng.', 'Cuối tuần chúng tôi hẹn môi giới đi xem nhà.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-b42302847cb2d49081f272f2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-62f8be843e19d02248bac94d.mp3', 3),
    ('中介', 'zhōngjiè', 'môi giới (bất động sản)', '这家中介服务态度很好，帮我们找到了合适的房子。', 'Zhè jiā zhōngjiè fúwù tàidu hěn hǎo, bāng wǒmen zhǎodào le héshì de fángzi.', 'Công ty môi giới này thái độ phục vụ rất tốt, giúp chúng tôi tìm được nhà phù hợp.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ab57dd92eac8aea458c61644.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-4f8416d1e924161caf362cda.mp3', 4),
    ('房东', 'fángdōng', 'chủ nhà', '房东要求租客每个月准时交房租。', 'Fángdōng yāoqiú zūkè měi gè yuè zhǔnshí jiāo fángzū.', 'Chủ nhà yêu cầu người thuê mỗi tháng nộp tiền nhà đúng hạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-f028763b3379b1fa681d1fd8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-109c281fe13330d48c4d37a4.mp3', 5),
    ('租客', 'zūkè', 'người thuê nhà', '租客需要签订正式的租房合同。', 'Zūkè xūyào qiāndìng zhèngshì de zūfáng hétóng.', 'Người thuê nhà cần ký hợp đồng thuê nhà chính thức.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-c3b7ac3c605dae7119c8497e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-97b60807bab0792599cfcdfe.mp3', 6),
    ('合租', 'hézū', 'thuê chung (cùng người khác thuê nhà)', '我们决定合租一个两室一厅的公寓。', 'Wǒmen juédìng hézū yī gè liǎng shì yī tīng de gōngyù.', 'Chúng tôi quyết định thuê chung một căn hộ hai phòng ngủ một phòng khách.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-a51678ea99809dec7aae3c21.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-490bc41d9c61fa09a0ad8a83.mp3', 7),
    ('整租', 'zhěngzū', 'thuê nguyên căn', '她选择整租一套三居室，方便一家人居住。', 'Tā xuǎnzé zhěngzū yī tào sān jū shì, fāngbiàn yī jiārén jūzhù.', 'Cô ấy chọn thuê nguyên căn 3 phòng ngủ, tiện cho cả gia đình sinh sống.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-363fb30626a092740ed3911b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-964a5d830cb53e4568052b3a.mp3', 8),
    ('单间', 'dānjiān', 'phòng đơn (phòng riêng nhỏ)', '这个单间带独立卫生间，租金包含水电费。', 'Zhège dānjiān dài dúlì wèishēngjiān, zūjīn bāohán shuǐdiàn fèi.', 'Phòng đơn này có nhà vệ sinh riêng, tiền thuê bao gồm điện nước.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ca4ac3a44eb49f12abf66a8c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-aa81b077db4c01f2c4de65b6.mp3', 9),
    ('一室一厅', 'yī shì yī tīng', 'một phòng ngủ, một phòng khách', '我找了一套一室一厅的公寓，离地铁很近。', 'Wǒ zhǎole yī tào yī shì yī tīng de gōngyù, lí dìtiě hěn jìn.', 'Tôi đã tìm được căn hộ một phòng ngủ một phòng khách, gần ga tàu điện ngầm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-3df24d6eea0902ffc821eff7.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-2bd32bf35a961be0707add8c.mp3', 10),
    ('小区', 'xiǎoqū', 'khu dân cư, khu chung cư', '小区环境安静，周边有很多便利设施。', 'Xiǎoqū huánjìng ānjìng, zhōubiān yǒu hěn duō biànlì shèshī.', 'Khu dân cư yên tĩnh, xung quanh có nhiều tiện ích thuận tiện.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-3ea9f36ef3d9c6b9024f66dd.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-5965e1b66837f3cbb7956e36.mp3', 11),
    ('地铁附近', 'dìtiě fùjìn', 'gần ga tàu điện ngầm', '这套房子地铁附近，交通非常方便。', 'Zhè tào fángzi dìtiě fùjìn, jiāotōng fēicháng fāngbiàn.', 'Căn nhà này gần ga tàu điện ngầm, giao thông rất thuận tiện.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-dd5292954c247d0451a813bc.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-5df7e31fcd5dcd301da1a62a.mp3', 12),
    ('家具齐全', 'jiājù qíquán', 'đầy đủ nội thất', '房间家具齐全，可以直接拎包入住。', 'Fángjiān jiājù qíquán, kěyǐ zhíjiē līn bāo rùzhù.', 'Phòng đầy đủ nội thất, có thể dọn vào ở ngay.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-96cb56519fa4648bce29d88f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-dc9f4a2070f3dc49842c3862.mp3', 13),
    ('拎包入住', 'līnbāo rùzhù', 'dọn vào ở luôn, không cần mua sắm thêm', '这套公寓家具齐全，可以拎包入住，非常省心。', 'Zhè tào gōngyù jiājù qíquán, kěyǐ līnbāo rùzhù, fēicháng shěngxīn.', 'Căn hộ này nội thất đầy đủ, có thể dọn vào ở luôn, rất tiện lợi.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-6fdaef1f107193da49eac572.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-52f05db0fbb4b565a80f9223.mp3', 14),
    ('入住日期', 'rùzhù rìqī', 'ngày vào ở', '请告诉我你的入住日期，好安排钥匙交接。', 'Qǐng gàosù wǒ nǐ de rùzhù rìqī, hǎo ānpái yàoshi jiāojiē.', 'Xin hãy cho tôi biết ngày bạn vào ở để sắp xếp bàn giao chìa khóa.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-928f496e77885cf7d4bcba01.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-803ddba15a3041f840d3dbda.mp3', 15),
    ('月租金', 'yuè zūjīn', 'tiền thuê nhà hàng tháng', '房东要求月租金提前一个月支付。', 'Fángdōng yāoqiú yuè zūjīn tíqián yī gè yuè zhīfù.', 'Chủ nhà yêu cầu tiền thuê nhà hàng tháng phải trả trước một tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-9c0b1a2632fcd6a4a6ad0910.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-9ba4612880df8b1738489bbb.mp3', 16),
    ('押金', 'yājīn', 'tiền đặt cọc', '租房时需要交两个月的押金。', 'Zūfáng shí xūyào jiāo liǎng gè yuè de yājīn.', 'Khi thuê nhà cần nộp tiền đặt cọc tương đương hai tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-6424e3f2122068ffd45af34e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-60136b21937b6d1757ff3229.mp3', 17),
    ('合同', 'hétóng', 'hợp đồng', '签合同前一定要仔细阅读条款。', 'Qiān hétóng qián yīdìng yào zǐxì yuèdú tiáokuǎn.', 'Trước khi ký hợp đồng phải đọc kỹ các điều khoản.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-06c891807ee3feec35e9eb7b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-d3d9b6e4bb5b7ffae71a7b90.mp3', 18),
    ('出租', 'chūzū', 'cho thuê', '这套房子由房东直接出租，没有中介费。', 'Zhè tào fángzi yóu fángdōng zhíjiē chūzū, méiyǒu zhōngjiè fèi.', 'Căn nhà này do chủ nhà trực tiếp cho thuê, không mất phí môi giới.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-1e76895bf54661bd5faeafe2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-899b17ed8fd00dbf7d1afd8d.mp3', 19),
    ('房租', 'fángzū', 'tiền thuê nhà', '房租包括水电费，按月支付。', 'Fángzū bāokuò shuǐdiàn fèi, àn yuè zhīfù.', 'Tiền thuê nhà bao gồm tiền điện nước, thanh toán theo tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-d6d8b50d89f686dd6c56104e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-507320699c3f80ebfdf0817f.mp3', 20),
    ('房型', 'fángxíng', 'loại hình căn hộ, kiểu phòng', '中介介绍了几种不同的房型供我们选择。', 'Zhōngjiè jièshào le jǐ zhǒng bùtóng de fángxíng gōng wǒmen xuǎnzé.', 'Môi giới giới thiệu vài loại hình căn hộ khác nhau để chúng tôi lựa chọn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-dbeb70190aefc1f0784e90f4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-252c3ce7a5b86b88bc5289aa.mp3', 21),
    ('带宽', 'dàikuān', 'băng thông internet', '房东承诺带宽稳定，适合远程办公。', 'Fángdōng chéngnuò dàikuān wěndìng, shìhé yuǎnchéng bàngōng.', 'Chủ nhà cam kết băng thông internet ổn định, phù hợp làm việc từ xa.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-18533369be9dfc9c21efc73e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-c8de6fdd38599b7c668291b0.mp3', 22),
    ('水电费', 'shuǐdiàn fèi', 'tiền nước và điện', '水电费按实际使用量每个月结算。', 'Shuǐdiàn fèi àn shíjì shǐyòng liàng měi gè yuè jiésuàn.', 'Tiền nước và điện được tính theo lượng sử dụng thực tế mỗi tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-39d45255f3fe747525613256.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-a4ee5f21f7c13fa87225f1ca.mp3', 23),
    ('公共区域', 'gōnggòng qūyù', 'khu vực chung (nhà chung, chung cư)', '公共区域需要租客共同保持清洁。', 'Gōnggòng qūyù xūyào zūkè gòngtóng bǎochí qīngjié.', 'Khu vực chung cần người thuê cùng nhau giữ gìn sạch sẽ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-9d900e19811e17898accb6b5.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-b265f8d10b4c6e28b252e5c3.mp3', 24),
    ('钥匙交接', 'yàoshi jiāojiē', 'bàn giao chìa khóa', '入住时要和房东做好钥匙交接手续。', 'Rùzhù shí yào hé fángdōng zuò hǎo yàoshi jiāojiē shǒuxù.', 'Khi vào ở phải làm thủ tục bàn giao chìa khóa với chủ nhà.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-272e8f2f61c0cf0a40fbe272.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-054ab5f240e4b703f517dcd8.mp3', 25),
    ('租金', 'zūjīn', 'Tiền thuê nhà', '租金必须在每月五日前按时缴纳。', 'Zūjīn bìxū zài měi yuè wǔ rì qián àn shí jiǎonà.', 'Tiền thuê nhà phải được thanh toán đúng hạn trước ngày mùng 5 mỗi tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-54a41d84849fbf258aaa3a37.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-64445ec1f4934716777be225.mp3', 26),
    ('付款期限', 'fùkuǎn qīxiàn', 'Thời hạn thanh toán', '合同中明确规定了付款期限和方式。', 'Hétóng zhōng míngquè guīdìng le fùkuǎn qīxiàn hé fāngshì.', 'Trong hợp đồng quy định rõ thời hạn và hình thức thanh toán.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ec15c95e02d28646d03159e2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-d5366ae8c39bba76eae129fa.mp3', 27),
    ('付款方式', 'fùkuǎn fāngshì', 'Phương thức thanh toán', '租金的付款方式可以选择转账或现金。', 'Zūjīn de fùkuǎn fāngshì kěyǐ xuǎnzé zhuǎnzhàng huò xiànjīn.', 'Phương thức thanh toán tiền thuê có thể chọn chuyển khoản hoặc tiền mặt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-4e3c13589f98c0e6d397cec0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-be465e65000c6d9e6c32aa2c.mp3', 28),
    ('续租', 'xùzū', 'Gia hạn hợp đồng thuê', '租约到期后，租客可以申请续租。', 'Zūyuē dàoqī hòu, zūkè kěyǐ shēnqǐng xùzū.', 'Sau khi hợp đồng hết hạn, người thuê có thể xin gia hạn.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-0cc80142e893a0758da06aa9.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-fb4e2f8eb01777e26e658625.mp3', 29),
    ('退租', 'tuìzū', 'Trả nhà, chấm dứt thuê', '退租时请提前一个月通知房东。', 'Tuìzū shí qǐng tíqián yī ge yuè tōngzhī fángdōng.', 'Khi trả nhà xin vui lòng báo trước chủ nhà một tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-c8467faf9bcaa74881133a1e.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-a7e65ec78cc6230cca89bc7b.mp3', 30),
    ('违约金', 'wéiyuējīn', 'Tiền phạt vi phạm hợp đồng', '迟交房租会被收取一定数额的违约金。', 'Chí jiāo fángzū huì bèi shōuqǔ yīdìng shù''é de wéiyuējīn.', 'Trễ trả tiền thuê sẽ bị thu tiền phạt theo hợp đồng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-96e34bbaacb77e3b6455db8d.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-ead5a18cfe5b14c1430368d0.mp3', 31),
    ('收据', 'shōujù', 'Biên lai', '支付房租后，房东应提供收据作为凭证。', 'Zhīfù fángzū hòu, fángdōng yīng tígōng shōujù zuòwéi píngzhèng.', 'Sau khi thanh toán tiền thuê, chủ nhà phải đưa biên lai làm bằng chứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-f1bd7f7711b02233aad936c4.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-9815f9e13048daeed8660884.mp3', 32),
    ('转账', 'zhuǎnzhàng', 'Chuyển khoản', '请将房租转账到指定的银行账户。', 'Qǐng jiāng fángzū zhuǎnzhàng dào zhǐdìng de yínháng zhànghù.', 'Vui lòng chuyển tiền thuê nhà đến tài khoản ngân hàng đã định.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-4c3be7e0b72ee604e42c8021.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-5dc96d94626f8ff06b60cfae.mp3', 33),
    ('退押金', 'tuì yājīn', 'Hoàn trả tiền đặt cọc', '退租后，房东应在七个工作日内退押金。', 'Tuìzū hòu, fángdōng yīng zài qī ge gōngzuòrì nèi tuì yājīn.', 'Sau khi trả nhà, chủ nhà phải trả lại tiền đặt cọc trong 7 ngày làm việc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-88687ec9b40915efe0968d49.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-2058c5c198e1f8a7cd3cef3d.mp3', 34),
    ('租期', 'zūqī', 'Thời hạn thuê nhà', '租赁合同上注明了具体的租期和终止日期。', 'Zūlìn hétóng shàng zhùmíng le jùtǐ de zūqī hé zhōngzhǐ rìqī.', 'Trên hợp đồng thuê nhà ghi rõ thời hạn thuê và ngày kết thúc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-6c3e2a8be8e803784e4cf987.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-a4a7745554d86885bbe83f82.mp3', 35),
    ('月付', 'yuèfù', 'Thanh toán hàng tháng', '合同约定租金按月付，月底之前必须支付。', 'Hétóng yuēdìng zūjīn àn yuèfù, yuèdǐ zhīqián bìxū zhīfù.', 'Hợp đồng quy định tiền thuê trả hàng tháng, phải thanh toán trước cuối tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-40c1939cc6501d3c0f10f887.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-de5f5db2e572d7cb555e9cc9.mp3', 36),
    ('季付', 'jìfù', 'Thanh toán hàng quý', '房东同意租金以季付方式收取。', 'Fángdōng tóngyì zūjīn yǐ jìfù fāngshì shōuqǔ.', 'Chủ nhà đồng ý nhận tiền thuê theo phương thức thanh toán hàng quý.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-0335624140f506a099f69a33.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-180892498e687ce3fc74cce5.mp3', 37),
    ('年付', 'niánfù', 'Thanh toán hàng năm', '租客选择年付租金以获得折扣优惠。', 'Zūkè xuǎnzé niánfù zūjīn yǐ huòdé zhékòu yōuhuì.', 'Người thuê lựa chọn trả tiền thuê hàng năm để được giảm giá.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ef739be52a05071e7cd30686.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-81e4d9ac5a02ed97b8864d77.mp3', 38),
    ('签字', 'qiānzì', 'Ký tên', '请在合同最后一页签字确认协议内容。', 'Qǐng zài hétóng zuìhòu yī yè qiānzì quèrèn xiéyì nèiróng.', 'Vui lòng ký tên xác nhận nội dung thỏa thuận ở trang cuối hợp đồng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-c2cd6d78203cb757b78ab696.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-4767545cd116fe9111801a41.mp3', 39),
    ('合同条款', 'hétóng tiáokuǎn', 'Điều khoản hợp đồng', '租赁合同条款需要双方仔细阅读并理解。', 'Zūlìn hétóng tiáokuǎn xūyào shuāngfāng zǐxì yuèdú bìng lǐjiě.', 'Điều khoản hợp đồng thuê cần hai bên đọc kỹ và hiểu rõ.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-6694df2c98392db38c689aa8.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-eda1bd144ad9522f5206dfb7.mp3', 40),
    ('合同期限', 'hétóng qīxiàn', 'Thời hạn hợp đồng', '合同期限为一年的租房协议。', 'Hétóng qīxiàn wèi yī nián de zūfáng xiéyì.', 'Thời hạn hợp đồng là thỏa thuận thuê nhà trong vòng một năm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-dc45995d3c3f8b597122cb62.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-a84a5ea45ec50843854100a6.mp3', 41),
    ('提前通知', 'tíqián tōngzhī', 'Thông báo trước', '退租需提前通知房东，通常至少提前一个月。', 'Tuìzū xū tíqián tōngzhī fángdōng, tōngcháng zhìshǎo tíqián yī ge yuè.', 'Khi trả nhà phải thông báo trước chủ nhà, thường ít nhất một tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-bb3255b5b3ee048c7b387b2b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-ed21cda9622b3ce761c38fc6.mp3', 42),
    ('结算日', 'jiésuàn rì', 'Ngày thanh toán cuối', '合同规定租金结算日为每季度的最后一天。', 'Hétóng guīdìng zūjīn jiésuàn rì wèi měi jìdù de zuìhòu yī tiān.', 'Hợp đồng quy định ngày thanh toán tiền thuê là ngày cuối của mỗi quý.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-131448da7751333e9332b4ff.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-97fd52a743633563c5c71db7.mp3', 43),
    ('租赁期限延长', 'zūlìn qīxiàn yáncháng', 'Gia hạn thời hạn thuê', '双方协商一致后，租赁期限延长半年。', 'Shuāngfāng xiéshāng yīzhì hòu, zūlìn qīxiàn yáncháng bàn nián.', 'Sau khi hai bên đồng thuận, thời hạn thuê được gia hạn thêm nửa năm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-e1ef5181c528d327d1e5889f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-038013a4b87b000bdd5b9e54.mp3', 44),
    ('押金退还期限', 'yājīn tuìhuán qīxiàn', 'Thời hạn hoàn trả tiền cọc', '合同规定押金退还期限为租期结束后十五天内。', 'Hétóng guīdìng yājīn tuìhuán qīxiàn wèi zūqī jiéshù hòu shíwǔ tiān nèi.', 'Hợp đồng quy định thời hạn hoàn trả tiền đặt cọc là trong vòng 15 ngày sau khi kết thúc thuê.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-acb6e47226e75d878cc6b472.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-f935a046bf9418141b2c1ecc.mp3', 45),
    ('清洁费用', 'qīngjié fèiyòng', 'Phí vệ sinh', '退租时需支付一定的清洁费用。', 'Tuìzū shí xū zhīfù yīdìng de qīngjié fèiyòng.', 'Khi trả nhà cần phải thanh toán khoản phí vệ sinh nhất định.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-af2adf3c64804c630c360f52.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-e67b022eda49f2eebbacb596.mp3', 46),
    ('付清', 'fù qīng', 'Thanh toán đầy đủ', '租客必须在合同结束前付清所有欠款。', 'Zūkè bìxū zài hétóng jiéshù qián fù qīng suǒyǒu qiànkuǎn.', 'Người thuê phải thanh toán đầy đủ mọi khoản nợ trước khi hợp đồng kết thúc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ab5cee918d27eb7e284ae484.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-37c90b52a613d50936e3f83f.mp3', 47),
    ('违约责任', 'wéiyuē zérèn', 'Trách nhiệm vi phạm hợp đồng', '违约责任由违约方承担相应的赔偿费用。', 'Wéiyuē zérèn yóu wéiyuē fāng chéngdān xiāngyìng de péicháng fèiyòng.', 'Trách nhiệm vi phạm hợp đồng do bên vi phạm chịu chi phí bồi thường tương ứng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-c0278210d51df59ce600b6e3.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-cfa3c8902eb2497790ee1e41.mp3', 48),
    ('到账时间', 'dàozhàng shíjiān', 'Thời gian nhận được tiền', '转账后请确认到账时间以避免误会。', 'Zhuǎnzhàng hòu qǐng quèrèn dàozhàng shíjiān yǐ bìmiǎn wùhuì.', 'Sau khi chuyển khoản xin xác nhận thời gian tiền đến tài khoản để tránh hiểu lầm.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-142591d5824a412d437953e6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-0ea8a9dc0b62df9616521919.mp3', 49),
    ('租赁押金协议', 'zūlìn yājīn xiéyì', 'Thỏa thuận tiền đặt cọc thuê nhà', '签订租赁押金协议确保押金安全和退还规则。', 'Qiāndìng zūlìn yājīn xiéyì quèbǎo yājīn ānquán hé tuìhuán guīzé.', 'Ký thỏa thuận tiền đặt cọc thuê nhà để bảo đảm an toàn và quy định hoàn trả tiền cọc.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-8148c0e48be60c0a532971fb.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-dfaa1b87f7547c32556794d8.mp3', 50),
    ('水费', 'shuǐ fèi', 'Tiền nước', '每个月的水费需要在月底之前支付。', 'Měi gè yuè de shuǐ fèi xū yào zài yuè dǐ zhī qián zhī fù.', 'Tiền nước hàng tháng cần phải thanh toán trước cuối tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-61afbbe1684390b3e928137b.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-fe2555f3fbb927763a09e840.mp3', 51),
    ('电费', 'diàn fèi', 'Tiền điện', '电费账单通常在每月十号发出。', 'Diàn fèi zhàng dān tōng cháng zài měi yuè shí hào fā chū.', 'Hóa đơn tiền điện thường được gửi vào ngày 10 hàng tháng.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-ab8cff9a597a39f0bce28267.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-37d631fa27a9e4ff09d4c5a8.mp3', 52),
    ('燃气费', 'rán qì fèi', 'Tiền gas', '冬天使用燃气费会比夏天高一些。', 'Dōng tiān shǐ yòng rán qì fèi huì bǐ xià tiān gāo yī xiē.', 'Tiền gas dùng vào mùa đông sẽ cao hơn mùa hè một chút.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-805b9e930188287293e7cee6.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-08c1629795913f702a07fe11.mp3', 53),
    ('物业费', 'wù yè fèi', 'Phí quản lý tòa nhà', '物业费包括公共区域的清洁和维护。', 'Wù yè fèi bāo kuò gōng gòng qū yù de qīng jié hé wéi hù.', 'Phí quản lý bao gồm việc dọn dẹp và bảo trì khu vực chung.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-40d63527f72774d55175691c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-be41bd068c1fdd34428e2d33.mp3', 54),
    ('网费', 'wǎng fèi', 'Tiền mạng internet', '网费一般按月缴纳，可以选择不同套餐。', 'Wǎng fèi yì bān àn yuè jiǎo nà, kě yǐ xuǎn zé bù tóng tào cān.', 'Tiền mạng thông thường trả theo tháng, có thể chọn các gói khác nhau.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-673869a995d0c259bc23dcda.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-b4dad1de6c8d4ceb66edb87a.mp3', 55),
    ('水表', 'shuǐ biǎo', 'Đồng hồ nước', '水表安装在厨房外墙上，方便抄表。', 'Shuǐ biǎo ān zhuāng zài chú fáng wài qiáng shàng, fāng biàn chāo biǎo.', 'Đồng hồ nước được lắp ngoài tường bếp để dễ đọc số.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-47a218206bab32848dcac2d2.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-4e92c2c52c30decf40eccc3d.mp3', 56),
    ('电表', 'diàn biǎo', 'Đồng hồ điện', '请定期检查电表，确保无异常。', 'Qǐng dìng qī jiǎn chá diàn biǎo, què bǎo wú yì cháng.', 'Vui lòng kiểm tra đồng hồ điện định kỳ để đảm bảo không có bất thường.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-0b2c37b26bab47a8f68cf80c.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-36ac6fa5af8fe94bbb30f77b.mp3', 57),
    ('热水器', 'rè shuǐ qì', 'Bình nước nóng', '热水器坏了需要联系物业维修。', 'Rè shuǐ qì huài le xū yào lián xì wù yè wéi xiū.', 'Bình nước nóng hỏng cần liên hệ với ban quản lý tòa nhà sửa chữa.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/word-c9c5e4d85c5cbdf07b76d6a3.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/thue-nha-sinh-hoat-trung-quoc-150/sentence-a7b67660fb227a1af149b523.mp3', 58),
